import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.aYYe0dfI.js";const f=JSON.parse('{"title":"Module extract:filter","description":"The extract:filter module provides path resolution and filtering utilities used during the extraction process. It defines public functions such as resolve_path_under_directory, canonical_graph_path, and project_relative_path that normalize and compute relative paths from project roots. Filtering capabilities are exposed through matches_filter and path_prefix_matches, which check inclusion criteria and directory ancestry. The PathResolveError struct reports failures when a path cannot be resolved to a filesystem location. Together, these components manage scope restrictions and path transformations essential for extracting relevant source artifacts.","frontmatter":{"title":"Module extract:filter","description":"The extract:filter module provides path resolution and filtering utilities used during the extraction process. It defines public functions such as resolve_path_under_directory, canonical_graph_path, and project_relative_path that normalize and compute relative paths from project roots. Filtering capabilities are exposed through matches_filter and path_prefix_matches, which check inclusion criteria and directory ancestry. The PathResolveError struct reports failures when a path cannot be resolved to a filesystem location. Together, these components manage scope restrictions and path transformations essential for extracting relevant source artifacts.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/extract/filter.md","filePath":"en/clore/modules/extract/filter.md"}'),i={name:"clore/modules/extract/filter.md"};function c(s,e,l,d,n,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="module-extract-filter" tabindex="-1">Module <code>extract:filter</code> <a class="header-anchor" href="#module-extract-filter" aria-label="Permalink to &quot;Module `extract:filter`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>extract:filter</code> module provides path resolution and filtering utilities used during the extraction process. It defines public functions such as <code>resolve_path_under_directory</code>, <code>canonical_graph_path</code>, and <code>project_relative_path</code> that normalize and compute relative paths from project roots. Filtering capabilities are exposed through <code>matches_filter</code> and <code>path_prefix_matches</code>, which check inclusion criteria and directory ancestry. The <code>PathResolveError</code> struct reports failures when a path cannot be resolved to a filesystem location. Together, these components manage scope restrictions and path transformations essential for extracting relevant source artifacts.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./merge"><code>extract:merge</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-pathresolveerror" tabindex="-1"><code>clore::extract::PathResolveError</code> <a class="header-anchor" href="#clore-extract-pathresolveerror" aria-label="Permalink to &quot;`clore::extract::PathResolveError`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:8</code></p><p>Definition: <code>extract/filter.cppm:8</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The struct <code>clore::extract::PathResolveError</code> consists of a single public member, <code>std::string message</code>, which stores a human-readable description of the resolution failure. No additional invariants are enforced beyond those inherent to <code>std::string</code>; the member is intended to be populated at construction or assignment time. All special member functions (default constructor, copy/move constructors, copy/move assignment, destructor) are implicitly defined by the compiler, meaning the struct is trivially copyable and movable via the corresponding operations of <code>std::string</code>. This lightweight design allows the error type to be passed and stored efficiently without custom resource management.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> member is always initialized (default-constructed or assigned).</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>std::string message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Constructed with a descriptive error message when path resolution fails.</li><li>Likely returned as an error from functions or stored in <code>std::expected</code> or similar error-handling mechanisms.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-canonical-graph-path" tabindex="-1"><code>clore::extract::canonical_graph_path</code> <a class="header-anchor" href="#clore-extract-canonical-graph-path" aria-label="Permalink to &quot;`clore::extract::canonical_graph_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:21</code></p><p>Definition: <code>extract/filter.cppm:103</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::canonical_graph_path</code> normalises a given <code>std::filesystem::path</code> into a uniform, platform-independent string suitable for graph contexts. It first attempts to compute an absolute path via <code>fs::absolute</code>; if successful, it applies <code>fs::weakly_canonical</code> on the lexically-normalised absolute form. Should that second step fail, it falls back to the absolute normalised path’s <code>generic_string</code>. If the initial absolute resolution itself fails (e.g., due to a non-existent component), the function computes a lexically-normalised version of the original path and tries <code>fs::weakly_canonical</code> on that; as a final fallback, it returns the normalised string directly. Throughout, <code>std::error_code</code> captures filesystem errors, ensuring that no exceptions propagate from the standard library calls, and the returned string always uses forward slashes via <code>generic_string</code>.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the input <code>path</code> parameter</li><li>filesystem state (to resolve absolute and canonical paths)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>normalizing paths for dependency graph nodes</li><li>computing a unique key for a filesystem path</li></ul><h3 id="clore-extract-filter-root-path" tabindex="-1"><code>clore::extract::filter_root_path</code> <a class="header-anchor" href="#clore-extract-filter-root-path" aria-label="Permalink to &quot;`clore::extract::filter_root_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:27</code></p><p>Definition: <code>extract/filter.cppm:161</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function evaluates two candidate root paths from the provided <code>config</code> object. It first checks whether <code>config.workspace_root</code> is non‑empty; if so, it returns that path normalized via <code>lexically_normal()</code>. Otherwise, it falls back to normalizing <code>config.project_root</code>. This simple conditional ensures that when a workspace root is configured, it takes precedence as the filter root, while a project root serves as the default. No further transformation or validation is performed on the selected path.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>config<code>.workspace_root</code></li><li>config<code>.project_root</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Obtain the normalized root path for filtering operations.</li></ul><h3 id="clore-extract-matches-filter" tabindex="-1"><code>clore::extract::matches_filter</code> <a class="header-anchor" href="#clore-extract-matches-filter" aria-label="Permalink to &quot;`clore::extract::matches_filter`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:23</code></p><p>Definition: <code>extract/filter.cppm:124</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::matches_filter</code> determines whether a given <code>file</code> should be processed based on a <code>config::FilterRule</code> with include and exclude patterns, relative to a <code>filter_root</code> directory. It begins by normalising both the <code>file</code> path and the <code>filter_root</code> via <code>canonical_graph_path</code>, then computes a relative path from the root to the file using <code>project_relative_path</code>. If the relative path cannot be obtained (e.g. the file lies outside the root), the function immediately returns <code>false</code>.</p><p>Internally, the algorithm proceeds in two phases. If the <code>filter.include</code> list is non-empty, it iterates over each pattern and tests <code>path_prefix_matches</code> against the relative path string; if no pattern matches, the function returns <code>false</code>. Regardless of include filtering, it then iterates over the <code>filter.exclude</code> list; if any exclusion pattern matches, the function returns <code>false</code>. Only if the relative path satisfies both the include (or absence of include rules) and the exclude rule set does it return <code>true</code>. The core dependencies are <code>canonical_graph_path</code> for path normalisation, <code>project_relative_path</code> for relative path computation, and <code>path_prefix_matches</code> for pattern matching against the generic string representation of the relative path.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>file</code> (const <code>std::string</code>&amp;)</li><li>parameter <code>filter</code> (const <code>config::FilterRule</code>&amp;)</li><li>parameter <code>filter_root</code> (const <code>std::filesystem::path</code>&amp;)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>filtering source files during symbol extraction</li><li>applying user-defined include/exclude rules</li></ul><h3 id="clore-extract-path-prefix-matches" tabindex="-1"><code>clore::extract::path_prefix_matches</code> <a class="header-anchor" href="#clore-extract-path-prefix-matches" aria-label="Permalink to &quot;`clore::extract::path_prefix_matches`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:12</code></p><p>Definition: <code>extract/filter.cppm:33</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::path_prefix_matches</code> determines whether a given <code>relative</code> path string starts with a <code>pattern</code> such that the match occurs at a directory boundary. It first strips any trailing slashes from <code>pattern</code>; if the result is empty it immediately returns <code>false</code>. When the pattern contains a slash, it performs a prefix check using <code>relative.starts_with(pattern)</code> and then validates that the remainder of <code>relative</code> is either empty or begins with another slash, ensuring the match respects path component boundaries. For patterns without a slash (i.e., a single name component), the function checks whether <code>relative</code> exactly equals <code>pattern</code>, or, if <code>relative</code> is longer, whether it starts with <code>pattern</code> followed by a slash. The implementation relies solely on <code>std::string_view</code> operations such as <code>empty()</code>, <code>back()</code>, <code>remove_suffix()</code>, <code>find()</code>, <code>starts_with()</code>, <code>size()</code>, and indexing, with no external dependencies or side effects.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>relative</code></li><li><code>pattern</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to filter compilation entries by file path prefixes</li><li>Applied when checking if a source file belongs to a given directory pattern</li></ul><h3 id="clore-extract-project-relative-path" tabindex="-1"><code>clore::extract::project_relative_path</code> <a class="header-anchor" href="#clore-extract-project-relative-path" aria-label="Permalink to &quot;`clore::extract::project_relative_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:14</code></p><p>Definition: <code>extract/filter.cppm:64</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The implementation computes a relative path from <code>root_path</code> to <code>file</code> by calling <code>std::filesystem::path::lexically_relative</code> on <code>file</code> with <code>root_path</code>. This operation produces a path whose first component would place the starting location inside <code>root_path</code>; the result is stored in <code>rel</code>. If <code>rel</code> is empty—meaning the two paths are identical or <code>lexically_relative</code> could not produce a meaningful relative form—the function immediately returns <code>std::nullopt</code>. Otherwise, it iterates over each component of <code>rel</code>; if any component equals <code>&quot;..&quot;</code>, the path escapes <code>root_path</code>, and the function again returns <code>std::nullopt</code>. Only when all components are within <code>root_path</code> does it return <code>rel</code> wrapped in <code>std::optional</code>. The entire control flow relies solely on standard library path operations and involves no external project‑specific dependencies.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>file</code> (const ref)</li><li><code>root_path</code> (const ref)</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>path validation before extraction</li><li>ensuring file is within project root</li></ul><h3 id="clore-extract-resolve-path-under-directory" tabindex="-1"><code>clore::extract::resolve_path_under_directory</code> <a class="header-anchor" href="#clore-extract-resolve-path-under-directory" aria-label="Permalink to &quot;`clore::extract::resolve_path_under_directory`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:18</code></p><p>Definition: <code>extract/filter.cppm:79</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The function <code>clore::extract::resolve_path_under_directory</code> resolves a file path from a compilation database entry against an associated directory. It first checks if the input <code>path</code> is empty, returning a <code>PathResolveError</code> with an appropriate message if so. For a relative <code>path</code>, it verifies that the provided <code>directory</code> is non‑empty; if empty, it returns an error indicating that a directory is required. Otherwise, it forms an absolute path by combining <code>directory</code> and <code>path</code> using the <code>/</code> <code>operator</code> on <code>std::filesystem::path</code>. Finally, the result is normalized via <code>lexically_normal()</code> and returned as a valid <code>std::expected</code>. The function relies solely on the <code>std::filesystem</code> library and the custom <code>PathResolveError</code> struct; no other project utilities are invoked.</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>const <code>std::string</code>&amp; path</li><li>const <code>std::string</code>&amp; directory</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Resolve compilation database entry file path</li><li>Normalize relative source paths</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>extract:filter</code> module is decomposed into two conceptual layers: path resolution utilities and filtering predicates. The resolution layer—comprising <code>resolve_path_under_directory</code>, <code>canonical_graph_path</code>, <code>project_relative_path</code>, and <code>path_prefix_matches—handles</code> normalization, prefix checking, and derivation of relative paths using opaque integer path handles, relying on <code>std</code> for underlying filesystem operations. The filtering layer (<code>matches_filter</code>, <code>filter_root_path</code>) applies inclusion or root-scoping rules, drawing configuration from the <code>config</code> module and using the resolution utilities to validate filtered paths. Error conditions from resolution are explicitly represented by the public <code>PathResolveError</code> struct, which carries an error message. Implementation structure separates public interface in the primary module (filter<code>.cppm</code>) from internal details, with all public symbols declared at module scope and no further internal submodules indicated.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li></ul>',91)])])}const u=t(i,[["render",c]]);export{f as __pageData,u as default};
